// src/components/Contact.jsx
import { useState } from 'react';
import { personal } from '../data/portfolio';

const contactItems = [
  { icon: '✉', label: 'Email', val: 'ruben14marco@gmail.com', href: `mailto:${personal.contact.email}` },
  { icon: 'in', label: 'LinkedIn', val: 'rubén-marco-aa992b234', href: personal.contact.linkedin },
  { icon: '🌐', label: 'Portfolio', val: 'www.unsitiogenial.es', href: personal.contact.portfolio },
];

export default function Contact() {
  const [hovered, setHovered] = useState(null);

  return (
    <section id="contact" style={s.section}>
      <div style={s.inner}>
        <div className="reveal">
          <p style={s.label}>Contact / Contacto</p>
          <h2 style={s.title}>Let's talk</h2>
          <p style={s.sub}>¿Tienes una oportunidad en mente? Escríbeme y hablamos.</p>
        </div>

        <div style={s.grid}>
          {/* Links */}
          <div className="reveal" style={s.links}>
            {contactItems.map((item, i) => (
              <a
                key={i}
                href={item.href}
                target={item.href.startsWith('mailto') ? undefined : '_blank'}
                rel="noreferrer"
                style={{
                  ...s.link,
                  ...(hovered === i ? s.linkHover : {}),
                }}
                onMouseEnter={() => setHovered(i)}
                onMouseLeave={() => setHovered(null)}
              >
                <div style={s.linkIcon}>{item.icon}</div>
                <div>
                  <div style={s.linkLabel}>{item.label}</div>
                  <div style={s.linkVal}>{item.val}</div>
                </div>
                <span style={s.arrow}>→</span>
              </a>
            ))}

            <div style={s.availBadge}>
              <span style={s.availDot} />
              <span>Disponible para nuevas oportunidades</span>
            </div>
          </div>

          {/* Form */}
          <div className="reveal reveal-delay-2" style={s.form}>
            <div style={s.formGroup}>
              <label style={s.formLabel}>Tu nombre</label>
              <input style={s.input} type="text" placeholder="Juan García" />
            </div>
            <div style={s.formGroup}>
              <label style={s.formLabel}>Email</label>
              <input style={s.input} type="email" placeholder="juan@empresa.com" />
            </div>
            <div style={s.formGroup}>
              <label style={s.formLabel}>Asunto</label>
              <input style={s.input} type="text" placeholder="Oportunidad en tu empresa" />
            </div>
            <div style={s.formGroup}>
              <label style={s.formLabel}>Mensaje</label>
              <textarea style={s.textarea} rows={5} placeholder="Cuéntame sobre la oportunidad..." />
            </div>
            <a
              href={`mailto:${personal.contact.email}`}
              style={s.submit}
              onMouseEnter={e => { e.currentTarget.style.background = 'var(--accent2)'; e.currentTarget.style.transform = 'translateY(-2px)'; }}
              onMouseLeave={e => { e.currentTarget.style.background = 'var(--accent)'; e.currentTarget.style.transform = 'none'; }}
            >
              Enviar mensaje →
            </a>
          </div>
        </div>
      </div>
    </section>
  );
}

const s = {
  section:   { background: 'var(--bg2)', padding: '100px 5%' },
  inner:     { maxWidth: 1200, margin: '0 auto' },
  label:     { fontSize: 11, fontWeight: 600, letterSpacing: '0.2em', textTransform: 'uppercase', color: 'var(--accent)', marginBottom: 10 },
  title:     { fontFamily: 'var(--font-head)', fontSize: 'clamp(30px, 5vw, 50px)', fontWeight: 800, letterSpacing: '-2px', color: 'var(--text)', marginBottom: 10 },
  sub:       { fontSize: 16, color: 'var(--text2)', fontWeight: 300, marginBottom: 52 },
  grid:      { display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 60, alignItems: 'start' },
  links:     { display: 'flex', flexDirection: 'column', gap: 14 },
  link:      {
    display: 'flex', alignItems: 'center', gap: 16,
    padding: '18px 22px',
    background: 'var(--card)', border: '1px solid var(--border)',
    borderRadius: 10, textDecoration: 'none', color: 'var(--text)',
    transition: 'border-color 0.2s, transform 0.18s',
  },
  linkHover: { borderColor: 'rgba(232,58,58,0.3)', transform: 'translateX(5px)' },
  linkIcon:  {
    width: 40, height: 40, borderRadius: 8,
    background: 'rgba(232,58,58,0.09)',
    display: 'flex', alignItems: 'center', justifyContent: 'center',
    fontSize: 16, flexShrink: 0, fontWeight: 700,
  },
  linkLabel: { fontSize: 10, textTransform: 'uppercase', letterSpacing: '0.08em', color: 'var(--text3)', marginBottom: 2 },
  linkVal:   { fontSize: 14, color: 'var(--text)' },
  arrow:     { marginLeft: 'auto', color: 'var(--text3)', fontSize: 16 },
  availBadge:{ display: 'flex', alignItems: 'center', gap: 10, marginTop: 8, padding: '12px 16px', background: 'rgba(232,58,58,0.06)', border: '1px solid rgba(232,58,58,0.18)', borderRadius: 8, fontSize: 13, color: 'var(--accent2)' },
  availDot:  { display: 'inline-block', width: 7, height: 7, borderRadius: '50%', background: 'var(--accent)', animation: 'pulse 2s infinite', flexShrink: 0 },
  form:      { display: 'flex', flexDirection: 'column', gap: 16 },
  formGroup: { display: 'flex', flexDirection: 'column', gap: 6 },
  formLabel: { fontSize: 11, textTransform: 'uppercase', letterSpacing: '0.08em', color: 'var(--text3)' },
  input:     {
    background: 'var(--card)', border: '1px solid var(--border2)',
    borderRadius: 8, padding: '11px 15px',
    color: 'var(--text)', fontFamily: 'var(--font-body)', fontSize: 14,
    outline: 'none',
  },
  textarea:  {
    background: 'var(--card)', border: '1px solid var(--border2)',
    borderRadius: 8, padding: '11px 15px',
    color: 'var(--text)', fontFamily: 'var(--font-body)', fontSize: 14,
    outline: 'none', resize: 'vertical',
  },
  submit:    {
    background: 'var(--accent)', color: '#fff', border: 'none',
    padding: '13px 28px', borderRadius: 8,
    fontFamily: 'var(--font-body)', fontSize: 15, fontWeight: 500,
    cursor: 'pointer', textDecoration: 'none',
    textAlign: 'center', display: 'block',
    transition: 'background 0.2s, transform 0.15s',
    boxShadow: '0 4px 20px rgba(232,58,58,0.25)',
  },
};
